const products = $json.products || [];
return products.map(p => ({ json: {
  external_product_id: String(p.id),
  title: p.title,
  description: p.description,
  category: p.category,
  image_url: p.thumbnail,
  current_price: p.price,
  currency: 'USD',
  competitor_name: 'DemoMart'
}}));
